final:
module comparator_16bit (
    input [15:0] A,
    input [15:0] B,
    output reg A_equals_B,
    output reg A_greater_B,
    output reg A_less_B
);
  wire [15:0] _tap_A = A & {16{1'b1}};

    always @(*) begin
        A_equals_B = (A == B);
        A_greater_B = (A > B);
        A_less_B = (A < B);
    end
endmodule
